import React from "react";

const DashboardHome = () => {

  const data = {
    profit: 52000,
    loss: 7000,
    expense: 18000,
    inflation: 4.3
  };

  return (
    <div>

      <h1 className="text-3xl font-bold text-white mb-8">
        Vendor Dashboard
      </h1>

      <div className="grid grid-cols-4 gap-6">

        <div className="bg-green-500 p-6 rounded-lg text-white">
          <h2>Total Profit</h2>
          <p className="text-2xl font-bold">₹{data.profit}</p>
        </div>

        <div className="bg-red-500 p-6 rounded-lg text-white">
          <h2>Total Loss</h2>
          <p className="text-2xl font-bold">₹{data.loss}</p>
        </div>

        <div className="bg-yellow-500 p-6 rounded-lg text-white">
          <h2>Expense</h2>
          <p className="text-2xl font-bold">₹{data.expense}</p>
        </div>

        <div className="bg-blue-500 p-6 rounded-lg text-white">
          <h2>Inflation Impact</h2>
          <p className="text-2xl font-bold">{data.inflation}%</p>
        </div>

      </div>

    </div>
  );
};

export default DashboardHome;
